module shift_register_8bit(clk_inv, rst, load, D, SI, Q);
    input clk_inv, rst, load, SI;
    input [7:0] D;
    output reg [7:0] Q;

    always @(posedge clk_inv or posedge rst) begin
        if (rst)
            Q <= 8'b00000000;
        else if (load)
            Q <= D;
        else
            Q <= {Q[6:0], SI};
    end
endmodule
